SELECT * FROM (
    SELECT INNER_QRY.*, ROWNUM AS RNUM FROM (
        SELECT

        FROM SPW_CMS_ASSET a
        LEFT JOIN FWK_CODE c
          ON c.CODE_GROUP_ID = 'CMS00001'
         AND c.CODE = a.BUSINESS_CATEGORY
         AND c.USE_YN = 'Y'


    ) INNER_QRY
    WHERE ROWNUM <= #{endRow}
) WHERE RNUM > #{offset}

SELECT * FROM (
    SELECT INNER_QRY.*, ROWNUM AS RNUM FROM (
        SELECT

        FROM SPW_CMS_ASSET a
        LEFT JOIN FWK_CODE c
          ON c.CODE_GROUP_ID = 'CMS00001'
         AND c.CODE = a.BUSINESS_CATEGORY
         AND c.USE_YN = 'Y'


    ) INNER_QRY
    WHERE ROWNUM <= #{endRow}
) WHERE RNUM > #{offset}

